  const varsForId = [
    $json.startingFramePrompt,
  ];

  const MIN_LEN = 1;
  const MAX_LEN = 15;

  function stable(v){
    if (v === null || v === undefined) return "";
    if (typeof v === "string") return v;
    if (typeof v === "number" || typeof v === "boolean") return String(v);
    if (Array.isArray(v)) return "[" + v.map(stable).join(",") + "]";
    const keys = Object.keys(v).sort();
    return "{" + keys.map(k => JSON.stringify(k) + ":" + stable(v[k])).join(",") + "}";
  }

  const s = varsForId.map(stable).join("|");

  function fnv1a32(str){
    let h = 0x811c9dc5;
    for (let i = 0; i < str.length; i++){
      h ^= str.charCodeAt(i);
      h = Math.imul(h, 0x01000193);
    }
    return h >>> 0;
  }

  const seed1 = fnv1a32(s);
  const seed2 = fnv1a32("salt|" + s);

  const len = MIN_LEN + (seed1 % (MAX_LEN - MIN_LEN + 1));

  let state = (seed1 ^ seed2) >>> 0;
  function nextRand(){
    state = (Math.imul(state, 1664525) + 1013904223) >>> 0;
    return state;
  }

  let out = "";
  out += String((nextRand() % 9) + 1);

  while (out.length < len){
    out += String(nextRand() % 10);
  }

  return out;
})() }}

