let actions = []

const positivePrompt = $('filter ready start frames').item.json.positivePrompt
const negativePrompt = $('filter ready start frames').item.json.negativePrompt
const imageWidth = $('filter ready start frames').item.json.clipWidth
const imageHeight = $('filter ready start frames').item.json.clipHeight
const useLora = $('get all workflow params').first().json.useStyleLoraForStartFrame
const loraName = $('filter ready start frames').item.json.styleLoraName
const loraTriggerWord = $('filter ready start frames').item.json.styleLoraTriggerWord
const seed = $('filter ready start frames').item.json.seed

const changeImageResolitonAction = {
  type: "addNode",
  id: "113",
  overwrite: true,
  node: {
    class_type: "EmptyFlux2LatentImage",
    _meta: { title: "Empty Flux 2 Latent" },
    inputs: {
      width: imageWidth,
      height: imageHeight,
      batch_size: 1
    }
  }
}

const changeSeedAction = {
  type: "addNode",
  id: "114",
  overwrite: true,
  node: {
    class_type: "RandomNoise",
    _meta: { title: "RandomNoise" },
    inputs: {
      noise_seed: seed
    }
  }
}

const addPostitivePromptAction = {
  type: "addNode",
  id: "115",
  overwrite: true,
  node: {
    class_type: "CLIPTextEncode",
    _meta: { title: "CLIP Text Encode (Positive Prompt)" },
    inputs: {
      text: (useLora ? (loraTriggerWord + ', ') : '') + positivePrompt,
      clip: ["111", 0]
    }
  }
}

const removeLoraNodeAction = [
  {
    type: "connect",
    fromNodeId: "122",
    fromOutput: 0,
    toNodeId: "105",
    toInput: "model"
  },
  {
    type: "removeNode",
    nodeId: "116"
  }
]

actions.push(changeImageResolitonAction)
actions.push(changeSeedAction)
actions.push(addPostitivePromptAction)

if (!useLora){
  actions.push(...removeLoraNodeAction)
}

return actions

})() }}

